const globals = $('GlobalsT1').item.json;
let eventData = $json;
let output = {};

output.todoist_id = eventData.id;//Todoist Task ID
output.task_name = eventData.content;//Todoist Task Name

// Completion status
if($json.checked == false){
output.status = eventData.checked=false;
}
else if($json.is_completed == true){
output.status = eventData.checked=true;
}
// Completion status

//Priority
const priorityMap = {
  "1": "4",
  "2": "3",
  "3": "2",
  "4": "1"
};
const priorityKey = String(eventData.priority);
output.priority = priorityMap.hasOwnProperty(priorityKey) ? priorityMap[priorityKey] : "4";
//Priority

//Section
for (let i = 0; i < globals.sections.length; i++){
    if(eventData.section_id === globals.sections[i].Section_id)
    {
        output.section_name = globals.sections[i].Section_name;
        break;
    }
    else{
      output.section_name = "Inbox"
    }
}
//Section

//Start Date
if (eventData.due !== null){
output.start_date = eventData.due.date;
 if (eventData.due.date && eventData.due.date.includes("T")) {
  const { DateTime } = require('luxon');
  const utcDate = DateTime.fromISO(eventData.due.date);
  const istDate = utcDate.setZone(globals.timezone);
  output.start_date = istDate;
  }
}
//Start Date

//End Date , Recurring
if(eventData.due != null){
if(eventData.due.is_recurring == true){
  const extractBoth = (str) => {
  const dayMatch = str.match(/every\s+([^@]+?)(?:\s+(?:ending|at|starting)\s+|$)/i);
  const dateMatch = str.match(/ending\s+([\d-]+)/);
  const timeMatch = str.match(/at\s+(\w+)/);

  return {
    day: dayMatch ? dayMatch[1].trim() : null,
    date: dateMatch ? dateMatch[1] : null,
    time: timeMatch ? timeMatch[1] : null
  };
  };

  const dueString = eventData.due.string || "";
  const result = extractBoth(dueString);
  const endDate = result.date;
  const day = result.day;
//Recurrence
function normalizeDayName(day) {
  const dayLower = day.toLowerCase();
  const daysMap = {
    mon: "monday", monday: "monday",
    tue: "tuesday", tuesday: "tuesday",
    wed: "wednesday", wednesday: "wednesday",
    thu: "thursday", thursday: "thursday",
    fri: "friday", friday: "friday",
    sat: "saturday", saturday: "saturday",
    sun: "sunday", sunday: "sunday"
  };
  return daysMap[dayLower] || null;
}

function parseDays(input) {
  // Split by common separators, comma prioritized but allow spaces, semicolons, etc.
  const parts = input.split(/[\s,;]+/).map(s => s.trim()).filter(Boolean);
  const result = [];

  for (const part of parts) {
    // Check if it's a known day name
    const normalizedDay = normalizeDayName(part);
    if (normalizedDay) {
      result.push(normalizedDay);
      continue;
    }

    // Check for numeric day with suffix removal (1st, 22nd, 3rd, etc.)
    const numericPart = part.replace(/(st|nd|rd|th)$/i, '');
    const dayNum = parseInt(numericPart, 10);
    if (!isNaN(dayNum) && dayNum >= 1 && dayNum <= 31) {
      result.push(dayNum.toString());
    }
  }

  return result;
}

function parseRecurrence(day) {
  if (!day || typeof day !== 'string') return "";

  const singleKeywords = ["day", "week", "month", "year"];
  const inputLower = day.toLowerCase();

  // Check for keywords that represent period units
  if (singleKeywords.includes(inputLower)) {
    return inputLower;
  }

  // Otherwise parse as list or single day/date
  const daysArray = parseDays(day);
  if (daysArray.length > 0) {
    return daysArray.join(",");
  }

  return "";
}
output.recurrence = "every " + parseRecurrence(day);

//Recurrence  

//End Date
if(endDate){
      output.end_date = endDate;
      if(eventData.due.date !== undefined){
        output.end_date = endDate;
        if(eventData.due.date && eventData.due.date.includes("T")) {
          const { DateTime } = require('luxon');
          const utcDate = DateTime.fromISO(eventData.due.date);
          const istDate = utcDate.setZone(globals.timezone);
          const endtime = eventData.due.date.substring(String(istDate).indexOf("T")) + "+05:30";
        output.end_date = endDate + endtime ;
        }
      }
}
//End Date  
}
}
//End Date, Recurring

output.created_at = eventData.added_at;

return { json: output };

